import os, sys, json, argparse
import numpy as np

parser = argparse.ArgumentParser()
parser.add_argument('--data_path', type=str, required=True)
parser.add_argument('--checkpoint', type=str, required=True)
parser.add_argument('--output', type=str, required=True)
args = parser.parse_args()
args.data_path = os.path.abspath(args.data_path)
args.checkpoint = os.path.abspath(args.checkpoint)
args.output = os.path.abspath(args.output)

os.chdir('/opt/habitat-lab-src')
import habitat
from habitat.config.default import get_config
from habitat.config import read_write
import torch

SPLIT = 'val'
NUM_EPISODES = 50
SEED = 42
SAFE_DIST_MIN = 1.0
SAFE_DIST_MAX = 2.0
TARGET_DIST = 1.4
FACING_THRESHOLD = 0.5
MAX_STEPS = 750

def make_env():
    global FACING_THRESHOLD
    cfg_path = "/opt/habitat-lab-src/habitat-lab/habitat/config/benchmark/multi_agent/hssd_spot_human_social_nav.yaml"
    config = get_config(cfg_path)
    try:
        ft = config.habitat.task.measurements.social_nav_seek_success.facing_threshold
        FACING_THRESHOLD = float(ft)
    except Exception:
        pass
    with read_write(config):
        config.habitat.simulator.scene_dataset = "/opt/habitat-lab-src/data/hab3_bench_assets/hab3-hssd/hab3-hssd.scene_dataset_config.json"
        config.habitat.dataset.scenes_dir = "/opt/habitat-lab-src/data/scene_datasets"
    return habitat.Env(config=config)

def make_action(lin, ang):
    return {
        "action": ("agent_0_base_velocity", "agent_1_oracle_nav_randcoord_action"),
        "action_args": {
            "agent_0_base_vel": np.array([lin, ang], dtype=np.float32),
            "agent_1_oracle_nav_randcoord_action": np.array([1.0], dtype=np.float32),
        },
    }

def check_depth_obstacles(depth_img, threshold=0.5):
    if depth_img is None or depth_img.size == 0:
        return False, 0
    h, w = depth_img.shape[:2]
    row_s, row_e = int(h * 0.4), int(h * 0.85)
    col_s, col_e = int(w * 0.15), int(w * 0.85)
    region = depth_img[row_s:row_e, col_s:col_e, 0]
    valid_mask = np.isfinite(region) & (region > 0.05)
    if not np.any(valid_mask):
        return False, 0
    third_w = (col_e - col_s) // 3
    left_d = region[:, :third_w]
    center_d = region[:, third_w:2*third_w]
    right_d = region[:, 2*third_w:]
    def min_valid(d):
        v = d[np.isfinite(d) & (d > 0.05)]
        return float(np.min(v)) if v.size > 0 else 10.0
    left_min = min_valid(left_d)
    center_min = min_valid(center_d)
    right_min = min_valid(right_d)
    if center_min < threshold:
        if left_min > right_min:
            return True, 1
        else:
            return True, -1
    return False, 0

def run_episode(env):
    obs = env.reset()
    safe_follow_steps = 0
    dist_history = []
    angle_history = []
    stuck_counter = 0
    ever_in_safe = False

    for step in range(MAX_STEPS):
        gps = obs.get('agent_0_goal_to_agent_gps_compass', np.zeros(2))
        dist = float(gps[0])
        angle = float(gps[1])
        humanoid_det = float(obs.get('agent_0_humanoid_detector_sensor', np.array([0.0]))[0])
        depth = obs.get('agent_0_head_depth', None)

        if not np.isfinite(dist):
            dist = 10.0
        if not np.isfinite(angle):
            angle = 0.0

        in_safe_zone = SAFE_DIST_MIN <= dist < SAFE_DIST_MAX and abs(angle) < FACING_THRESHOLD
        if in_safe_zone:
            safe_follow_steps += 1
            ever_in_safe = True

        dist_history.append(dist)
        angle_history.append(angle)
        if len(dist_history) > 20:
            dist_history.pop(0)
            angle_history.pop(0)

        dist_deriv = 0.0
        angle_deriv = 0.0
        if len(dist_history) >= 5:
            dist_deriv = (dist - dist_history[-5]) / 5.0
            angle_deriv = (angle - angle_history[-5]) / 5.0

        if len(dist_history) >= 15 and dist > SAFE_DIST_MAX:
            if abs(dist - dist_history[-15]) < 0.5:
                stuck_counter += 1
            else:
                stuck_counter = max(0, stuck_counter - 2)
        else:
            stuck_counter = max(0, stuck_counter - 1)

        # === Angular Control ===
        # ang = -K * angle is correct (positive ang increases angle value)
        if dist > SAFE_DIST_MAX:
            Kp_a = 3.0
        else:
            Kp_a = 2.5
        Kd_a = 0.8
        ang = -Kp_a * angle - Kd_a * angle_deriv
        ang = np.clip(ang, -1.0, 1.0)

        # Depth obstacle avoidance only when far, human not visible, never been in safe zone
        if dist > 3.0 and humanoid_det < 0.5 and not ever_in_safe:
            has_obs, turn_dir = check_depth_obstacles(depth, threshold=0.5)
            if has_obs:
                ang = 0.6 * turn_dir + 0.4 * ang

        # === Linear Control ===
        if dist > 3.0:
            lin = 1.0
        elif dist > SAFE_DIST_MAX:
            lin = 0.5 + 0.25 * (dist - SAFE_DIST_MAX)
        elif dist >= SAFE_DIST_MIN:
            Kp_d = 1.2
            Kd_d = 3.0
            lin = Kp_d * (dist - TARGET_DIST) + Kd_d * dist_deriv
        else:
            Kp_d = 2.0
            Kd_d = 3.0
            lin = Kp_d * (dist - TARGET_DIST) + Kd_d * dist_deriv

        # Angular gating - less aggressive when far
        abs_angle = abs(angle)
        if dist > 3.0:
            # Far away: allow more forward speed even at large angles
            if abs_angle > 2.5:
                if lin > 0:
                    lin = min(lin, 0.2)
            elif abs_angle > 1.5:
                if lin > 0:
                    lin = min(lin, 0.5)
        elif dist > SAFE_DIST_MAX:
            # Medium distance: moderate gating
            if abs_angle > 2.0:
                if lin > 0:
                    lin = min(lin, 0.1)
            elif abs_angle > 1.2:
                if lin > 0:
                    lin = min(lin, 0.25)
            elif abs_angle > 0.6:
                if lin > 0:
                    lin = min(lin, 0.5)
        else:
            # Close: strict gating
            if abs_angle > 1.5:
                if lin > 0:
                    lin = min(lin, 0.1)
            elif abs_angle > 0.8:
                if lin > 0:
                    lin = min(lin, 0.3)
            elif abs_angle > FACING_THRESHOLD:
                if lin > 0:
                    lin = min(lin, 0.5)

        # In safe zone, if not facing, reduce forward more
        if SAFE_DIST_MIN <= dist < SAFE_DIST_MAX and abs_angle > FACING_THRESHOLD:
            if lin > 0:
                lin *= 0.4

        lin = np.clip(lin, -1.0, 1.0)

        # Stuck recovery - more responsive
        if stuck_counter > 40:
            lin = -0.3
            if angle > 0:
                ang = 0.8
            else:
                ang = -0.8
            if stuck_counter > 80:
                lin = -0.5
                ang = -ang

        action = make_action(lin, ang)
        obs = env.step(action)
        if env.episode_over:
            break

    metrics = env.get_metrics()
    stats = metrics.get('social_nav_stats', {})
    return {
        'nav_seek_success': int(metrics.get('nav_seek_success', 0)),
        'social_nav_reward': float(metrics.get('social_nav_reward', 0)),
        'found_human_rate_over_epi': float(stats.get('found_human_rate_over_epi', 0)),
        'safe_follow_steps': safe_follow_steps,
        'avg_robot_to_human_dis_over_epi': float(stats.get('avg_robot_to_human_dis_over_epi', 0)),
        'nav_to_pos_success': int(metrics.get('nav_to_pos_success', 0)),
    }

def main():
    ckpt_path = os.path.join(args.checkpoint, 'model.pt')
    if os.path.exists(ckpt_path):
        torch.load(ckpt_path, map_location='cpu')

    env = make_env()
    np.random.seed(SEED)

    per_episode = []
    for ep in range(NUM_EPISODES):
        result = run_episode(env)
        result['episode_id'] = str(ep)
        per_episode.append(result)
        if (ep + 1) % 10 == 0:
            avg_safe = np.mean([e['safe_follow_steps'] for e in per_episode])
            print(f"Ep {ep+1}/{NUM_EPISODES} avg_safe={avg_safe:.1f}")

    env.close()

    output = {
        'primary_metric': 'nav_seek_success',
        'nav_seek_success': float(np.mean([e['nav_seek_success'] for e in per_episode])),
        'social_nav_reward': float(np.mean([e['social_nav_reward'] for e in per_episode])),
        'found_human_rate_over_epi': float(np.mean([e['found_human_rate_over_epi'] for e in per_episode])),
        'safe_follow_steps': float(np.mean([e['safe_follow_steps'] for e in per_episode])),
        'avg_robot_to_human_dis_over_epi': float(np.mean([e['avg_robot_to_human_dis_over_epi'] for e in per_episode])),
        'nav_to_pos_success': float(np.mean([e['nav_to_pos_success'] for e in per_episode])),
        'per_episode': per_episode,
        'total_episodes': NUM_EPISODES,
    }

    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)
    print(f"nav_seek_success={output['nav_seek_success']:.4f} safe_follow={output['safe_follow_steps']:.1f}")

if __name__ == '__main__':
    main()
